const aiRaw = $input.first().json;
const research = $('🔍 Research Lead').first().json._research;
const leadData = $('🔍 Research Lead').first().json;
const config = leadData._config || {};

function parseAiOutput(raw) {
  try {
    let text = raw.output || raw.text || '';
    if (typeof text === 'object' && text && text.hook_A !== undefined) return text;
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const match = text.match(/\{[\s\S]*\}/);
    if (!match) return null;
    return JSON.parse(match[0]);
  } catch (error) {
    return null;
  }
}

function buildDeterministicCopy(r, cfg) {
  const cityPart = r.has_valid_city ? ` en ${r.city}` : '';
  const angle = r.best_angle || 'general';
  const niche = r.niche || 'salud';
  const reviewCount = parseInt(r.review_count || 0, 10) || 0;
  const rating = parseFloat(r.rating || 0) || 0;
  const offerText = cfg.offer_text || 'En Nova resolvemos preguntas frecuentes, filtramos intención y agendamos citas por WhatsApp sin que su equipo tenga que responder cada mensaje.';

  const hooksByAngle = {
    volume: [
      `${r.business_name}${cityPart} ya mueve un volumen importante de conversaciones por WhatsApp.`,
      `Cuando una clínica como ${r.business_name} crece, responder WhatsApp a tiempo se vuelve un cuello de botella.`
    ],
    reputation: [
      `${r.business_name} ya tiene buena reputación${rating ? ` (${rating}★)` : ''}; el siguiente cuello suele ser la velocidad de respuesta.`,
      `Una marca bien posicionada como ${r.business_name} pierde valor cuando el WhatsApp depende de respuesta manual.`
