const MAX_FU = config.max_followups || 3;
const FU_DELAY = config.followup_delay_days || 3;
const MAX_EMAILS = config.max_emails_per_run || 100;
const MIN_TIER = config.min_tier || 3;
const today = new Date(); today.setHours(0,0,0,0);
const eligible = [];
const seenEmails = new Set();
const stats = { noEmail: 0, invalid: 0, tierSkip: 0, done: 0, nicheSkip: 0, citySkip: 0, emailDuplicates: 0, total: allLeadsRaw.length, requested: bridge.quantity, effective_max: MAX_EMAILS };

// ── BLOQUE 1: INITIAL CONTACTS ──────────────────────
if (!onlyFollowups) {
  for (const item of noContactados) {
    const lead = item.json;
    if (isContactado(lead.contactado)) continue;

    let email = lead.email || lead.Email || lead.correo || null;
    if (!email || email === 'N/A' || email === 'n/a') { stats.noEmail++; continue; }
    if (!isValidEmail(email)) { stats.invalid++; continue; }
    email = email.trim().toLowerCase();

    if (seenEmails.has(email)) { stats.emailDuplicates++; continue; }
    seenEmails.add(email);

    const tierVal = parseTier(lead.tier);
    if (tierFilter > 0) { if (tierVal !== tierFilter) { stats.tierSkip++; continue; } }
    else { if (tierVal > MIN_TIER) { stats.tierSkip++; continue; } }
    if (nicheFilter && !(lead.niche || '').toLowerCase().includes(nicheFilter)) { stats.nicheSkip++; continue; }
    if (cityFilter && !(lead.city || '').toLowerCase().includes(cityFilter)) { stats.citySkip++; continue; }

    const leadId = (lead.lead_id || '').toString().trim();
    const oc = leadId ? outreachMap.get(leadId) : null;
    if (oc) continue;

    eligible.push({ json: { ...lead, email, _action: 'initial_contact', _followup_number: 0, _existing_angle: null, _tier_value: tierVal, _config: config, _has_leads: true }});
  }
}

// ── BLOQUE 2: FOLLOWUPS ─────────────────────────────
if (!onlyNew) {
  for (const [leadId, oc] of outreachMap) {
