    if (oc.followup_count >= MAX_FU) { stats.done++; continue; }

    let action = null, fuNum = 0;
    if (oc.next_followup_date && new Date(oc.next_followup_date) <= today) {
      action = 'followup'; fuNum = oc.followup_count + 1;
