      const days = Math.floor((today - new Date(oc.last_contact_date)) / 86400000);
      if (days >= FU_DELAY) { action = 'followup'; fuNum = oc.followup_count + 1; }
      else continue;
    } else continue;

    // ★ BUSCA EN leads_master PRIMERO, SI NO EXISTE USA outreach_control
    let lead = allLeadsMap.get(leadId);
