// ═══ 🔍 FIND DUPLICATES v1.0 ═══════════════════════════════════════════════
// Agrupa por email normalizado y por lead_id.
// Conserva el de mayor score; el resto son duplicados.
// Retorna los duplicados ordenados DESC por _row_number
// para que la eliminación posterior sea de abajo hacia arriba (sin desplazamiento).

const all = $input.all().map((item, idx) => ({
  ...item.json,
  _row_number: idx + 2   // fila 1 = encabezado, datos desde fila 2
}));

const dupRowNums = new Set();
const duplicates = [];

// ── Por email ──────────────────────────────────────────────────────────────
const byEmail = new Map();
for (const row of all) {
  const email = (row.email || '').trim().toLowerCase();
  if (!email || email === 'n/a' || !email.includes('@')) continue;
  if (!byEmail.has(email)) byEmail.set(email, []);
  byEmail.get(email).push(row);
}
for (const [, group] of byEmail) {
  if (group.length <= 1) continue;
  group.sort((a,b) => (parseFloat(b.score)||0) - (parseFloat(a.score)||0));
  for (let i = 1; i < group.length; i++) {
    if (!dupRowNums.has(group[i]._row_number)) {
      dupRowNums.add(group[i]._row_number);
      duplicates.push({ ...group[i], motivo_descarte: 'duplicado_email' });
    }
  }
}

// ── Por lead_id ────────────────────────────────────────────────────────────
const byId = new Map();
for (const row of all) {
  const id = (row.lead_id || '').toString().trim();
  if (!id) continue;
  if (!byId.has(id)) byId.set(id, []);
  byId.get(id).push(row);
}
for (const [, group] of byId) {
  if (group.length <= 1) continue;
  group.sort((a,b) => (parseFloat(b.score)||0) - (parseFloat(a.score)||0));
  for (let i = 1; i < group.length; i++) {
    if (!dupRowNums.has(group[i]._row_number)) {
      dupRowNums.add(group[i]._row_number);
      duplicates.push({ ...group[i], motivo_descarte: 'duplicado_lead_id' });
    }
  }
}

if (duplicates.length === 0) {
  return [{ json: {
    _has_duplicates: false,
    _total_leads: all.length,
    _duplicates_found: 0
  }}];
}

// CRÍTICO: ordenar DESC para borrar de abajo hacia arriba sin desplazamiento
duplicates.sort((a,b) => b._row_number - a._row_number);

const summary = {
